import { useState } from "react";
import { Login } from "./components/Login";
import { SelecionarPosto } from "./components/SelecionarPosto";
import { Checkin } from "./components/Checkin";
import { CheckOut } from "./components/CheckOut";
import { Menu } from "./components/Menu";
import { Posto } from "./components/Posto";
import { Dashboard } from "./components/Dashboard";

export default function App() {
  const [pagina, setPagina] = useState("login");
  const [token, setToken] = useState(localStorage.getItem("token"));
  const [postoAtivo, setPostoAtivo] = useState(
    localStorage.getItem("postoId")
      ? {
        id: localStorage.getItem("postoId"),
        nome: localStorage.getItem("postoNome"),
      }
      : null
  );
  const handleLoginSuccess = (data) => {
    const nivel = data?.tipo || "";
    setToken(data?.token);
    localStorage.setItem("token", data?.token);
    localStorage.setItem("nivelAcesso", nivel);
    localStorage.setItem("email", data?.email || "");
    setPagina(nivel === "PADRAO" ? "selecionar-posto" : "dashboard");
  };

  const handlePostoSelecionado = (posto) => {
    setPostoAtivo(posto);
    localStorage.setItem("postoId", posto.id);
    localStorage.setItem("postoNome", posto.nome);
    setPagina("dashboard");
  };

  const handleLogout = () => {
    setToken(null);
    setPostoAtivo(null);
    localStorage.clear();
    setPagina("login");
  };

  if (pagina === "login" || !token) {
    return <Login onLoginSuccess={handleLoginSuccess} />;
  }

  if (pagina === "selecionar-posto") {
    return <SelecionarPosto onPostoSelecionado={handlePostoSelecionado} onLogout={handleLogout} />;
  }

  if (pagina === "checkin") {
    return <Checkin posto={postoAtivo} onNavegar={setPagina} onLogout={handleLogout} />;
  }

  if (pagina === "checkout") {
    return <CheckOut posto={postoAtivo} onNavegar={setPagina} onLogout={handleLogout} />;
  }

  if (pagina === "menu") {
    return <Menu posto={postoAtivo} onNavegar={setPagina} onLogout={handleLogout} />;
  }

  if (pagina === "posto") {
    return <Posto onNavegar={setPagina} onLogout={handleLogout} />;
  }

  if (pagina === "dashboard") {
    return (
      <Dashboard
        posto={postoAtivo}
        onNavegar={setPagina}
        onLogout={handleLogout}
      />
    );
  }



  return <Login onLoginSuccess={handleLoginSuccess} />;
}
